using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

var dllPath = System.IO.Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/modelcontextprotocol/1.2.0/lib/net10.0/ModelContextProtocol.dll"
);

var xmlPath = System.IO.Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/modelcontextprotocol/1.2.0/lib/net10.0/ModelContextProtocol.xml"
);

Console.WriteLine("=== MODELCONTEXTPROTOCOL 1.2.0 REFLECTION ANALYSIS ===\n");
Console.WriteLine($"DLL: {dllPath}");
Console.WriteLine($"XML: {xmlPath}\n");

