var types = assembly.GetTypes().Where(t => t.IsPublic).OrderBy(t => t.Namespace + "." + t.Name).ToList();

Console.WriteLine($"Total Public Types: {types.Count}\n");

// Find attributes
Console.WriteLine("=== ATTRIBUTES/CUSTOM ATTRIBUTES ===");
var attributes = types.Where(t => typeof(Attribute).IsAssignableFrom(t)).OrderBy(t => t.Name).ToList();
foreach (var attr in attributes)
{
    Console.WriteLine($"\n[{attr.Name}]");
    Console.WriteLine($"  Namespace: {attr.Namespace}");
    Console.WriteLine($"  FullName: {attr.FullName}");

    // Show constructor parameters
    var ctors = attr.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    foreach (var ctor in ctors)
    {
        var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  Constructor: ({parms})");
    }

    // Show public properties
    var props = attr.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    foreach (var prop in props)
    {
        Console.WriteLine($"  Property: {prop.PropertyType.Name} {prop.Name} {{ get; {(prop.CanWrite ? "set" : "")}; }}");
    }
}

// Find extension methods for IHostBuilder and IServiceCollection
