    .Where(t => t.IsSealed && t.IsAbstract) // Static class indicator
    .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
    .Where(m => m.GetParameters().Length > 0 && m.GetParameters()[0].GetCustomAttribute<System.Runtime.CompilerServices.ExtensionAttribute>() != null)
    .OrderBy(m => m.DeclaringType.Name)
    .ThenBy(m => m.Name)
    .ToList();

