{
    Console.WriteLine($"\n=== Extension Methods on {group.Key} ===");
    foreach (var method in group.OrderBy(m => m.Name))
    {
        var parms = string.Join(", ", method.GetParameters().Skip(1).Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({parms})");
        Console.WriteLine($"    -> From: {method.DeclaringType.Name}");
    }
}

