{
    Console.WriteLine($"\n{t.Name}");
    Console.WriteLine($"  FullName: {t.FullName}");
    if (typeof(Attribute).IsAssignableFrom(t))
    {
        Console.WriteLine($"  [IS ATTRIBUTE]");
    }
}

Console.WriteLine("\n\n=== PROMPT-RELATED TYPES ===");
