    t.Name.Contains("Server", StringComparison.OrdinalIgnoreCase) ||
    t.Name.Contains("Host", StringComparison.OrdinalIgnoreCase) ||
    t.Name.Contains("Transport", StringComparison.OrdinalIgnoreCase) ||
    t.Name.Contains("Stdio", StringComparison.OrdinalIgnoreCase)
).OrderBy(t => t.Name).ToList();

foreach (var t in serverTypes)
{
    Console.WriteLine($"\n{t.Name}");
    Console.WriteLine($"  FullName: {t.FullName}");

    // Show public methods and properties
    var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName)
        .OrderBy(m => m.Name)
        .ToList();

    var props = t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);

    if (methods.Any() || props.Any())
    {
        if (props.Any())
        {
            Console.WriteLine($"  Properties:");
            foreach (var prop in props)
            {
                Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name}");
            }
        }

        if (methods.Any())
        {
            Console.WriteLine($"  Methods:");
            foreach (var method in methods.Take(10))
            {
                var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name}"));
                Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({parms})");
            }
            if (methods.Count > 10)
            {
                Console.WriteLine($"    ... and {methods.Count - 10} more");
            }
        }
    }
}

// All namespaces
Console.WriteLine("\n\n=== ALL NAMESPACES ===");
var namespaces = types.Select(t => t.Namespace).Distinct().OrderBy(n => n).ToList();
foreach (var ns in namespaces)
{
    Console.WriteLine($"  {ns}");
